def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_no_solution(nums, target):
    return all(num < target for num in nums) or all(num > target for num in nums)

def solve_with_checks(nums, target):
    if check_no_solution(nums, target):
        return -1, -1
    return solve(nums, target)

# Unit tests
def test_solve():
    assert solve([1, 2, 3, 4, 5], 5) == (0, 3)
    assert solve([1, 2, 3, 4, 5], 10) == -1, -1
    assert solve([1, 2, 3, 4, 5], 8) == (2, 4)
    assert solve([], 5) == -1, -1
    assert solve([1], 1) == -1, -1

# Adversarial/edge-case tests
def test_edge_cases():
    assert solve([1, 2, 3], 6) == -1, -1
    assert solve([1, 1, 1, 1], 2) == (0, 1)
    assert solve([1, 2, 3, 4, 5, 6], 12) == -1, -1

test_solve()
test_edge_cases()
